final class XmlFlattener {

    static Map<String, Object> flatten(Element root, int maxDepth, int maxNodes) {
        LinkedHashMap<String, Object> out = new LinkedHashMap<>(4096);
        Deque<Frame> stack = new ArrayDeque<>();
        stack.push(new Frame(root, pathSegment(root), 0));

        int nodes = 0;
        long childrenCount = 0;

        while (!stack.isEmpty()) {
            Frame f = stack.pop();
            Element e = f.element;
            int depth = f.depth;
            if (depth > maxDepth) continue;

            nodes++;
            if (nodes > maxNodes) throw new IllegalArgumentException("XML too complex: node limit exceeded: " + maxNodes);

            String basePath = f.path;

            NamedNodeMap attrs = e.getAttributes();
            if (attrs != null && attrs.getLength() > 0) {
                for (int i = 0; i < attrs.getLength(); i++) {
                    Node a = attrs.item(i);
                    String an = a.getNodeName();
                    String key = basePath + "/@" + an;
                    put(out, key, a.getNodeValue());
                }
            }

            String text = directText(e);
            if (!text.isEmpty()) {
                put(out, basePath + "/#text", text);
            }

            NodeList kids = e.getChildNodes();
            int elementKids = 0;
            for (int i = 0; i < kids.getLength(); i++) {
                if (kids.item(i).getNodeType() == Node.ELEMENT_NODE) elementKids++;
            }
            childrenCount += elementKids;

            Map<String, Integer> siblingIndex = new LinkedHashMap<>();
            for (int i = kids.getLength() - 1; i >= 0; i--) {
                Node k = kids.item(i);
                if (k.getNodeType() != Node.ELEMENT_NODE) continue;
                Element ke = (Element) k;
                String seg = pathSegment(ke);
                int idx = siblingIndex.getOrDefault(seg, 0) + 1;
                siblingIndex.put(seg, idx);
                String childPath = basePath + "/" + seg + "[" + idx + "]";
                stack.push(new Frame(ke, childPath, depth + 1));
            }
        }

        out.put("_nodesVisited", nodes);
        out.put("_childrenCount", childrenCount);
        return out;
    }

    private static void put(Map<String, Object> out, String key, String value) {
        Object existing = out.get(key);
        if (existing == null) {
            out.put(key, value);
        } else if (existing instanceof List) {
            @SuppressWarnings("unchecked")
            List<String> list = (List<String>) existing;
            list.add(value);
        } else {
            List<String> list = new ArrayList<>(4);
            list.add(String.valueOf(existing));
            list.add(value);
            out.put(key, list);
        }
    }

    private static String directText(Element e) {
        NodeList kids = e.getChildNodes();
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < kids.getLength(); i++) {
            Node n = kids.item(i);
            if (n.getNodeType() == Node.TEXT_NODE || n.getNodeType() == Node.CDATA_SECTION_NODE) {
                String t = n.getNodeValue();
                if (t != null) sb.append(t);
            }
        }
        String s = sb.toString().trim();
        if (s.length() > 1_000_000) s = s.substring(0, 1_000_000);
        return s;
    }

    private static String pathSegment(Element e) {
        String ln = e.getLocalName();
        if (ln != null && !ln.isEmpty()) return ln;
        String nn = e.getNodeName();
        return nn != null ? nn : "element";
    }

    private static final class Frame {
        final Element element;
        final String path;
        final int depth;
        Frame(Element element, String path, int depth) {
            this.element = element;
            this.path = path;
            this.depth = depth;
        }
    }
}

